function mapInputRow(row) {
  const mapped = {};
  for (const [key, val] of Object.entries(row)) {
    const apiCode = INPUT_MAP[key] || INPUT_MAP[key.toLowerCase()] || key;
    mapped[apiCode] = val;
  }
  return mapped;
}

const input = $input.first().json.body;
const tokenValid = await verifyToken(input.token);
if (!tokenValid) {
  return [{ json: { status: 'error', message: 'Sesion no valida o expirada. Vuelve a iniciar sesion.', errors: 1, success: 0, errorList: [{ sku: '-', message: 'Token invalido' }], csvBase64: '', csvFilename: '', products: [] } }];
}

const products = input.products || [];
const marketplace = input.marketplace || 'sprinter_es';
const includeDiscount = input.includeDiscount === true;
const promoTag = (input.promoTag || '').trim();
const isPT = marketplace === 'sportzone_pt';
const outputFormat = input.outputFormat || '';
const shipmentOrigin = input.shipmentOrigin || 'ES';
const vatPct = input.vatPct || 'ES-21%,PT-23%';

const results = [];
const errors = [];

for (const p of products) {
  try {
    const mapped = mapInputRow(p);
    const sku = mapped['_offer-sku'] || mapped['sku-de-vendedor'] || '';
    if (!sku) { errors.push({ sku: '?', message: 'SKU vacio' }); continue; }
    const ean = String(mapped['ean'] || '').trim();
    const priceRaw = mapped['price'] || '';
    const price = String(priceRaw).replace(',', '.').replace(/[^0-9.]/g, '');
    if (!price || isNaN(Number(price))) { errors.push({ sku, message: 'Precio invalido: ' + priceRaw }); continue; }
    const qtyRaw = mapped['quantity'] || '';
    const quantity = qtyRaw ? String(qtyRaw).replace(/[^0-9]/g, '') : '';
    let discountPrice = '';
    let discountStart = '';
    let discountEnd = '';
    if (includeDiscount) {
      const dpRaw = mapped['discount-price'] || '';
      if (dpRaw) {
        discountPrice = String(dpRaw).replace(',', '.').replace(/[^0-9.]/g, '');
        if (discountPrice && isNaN(Number(discountPrice))) { errors.push({ sku, message: 'Precio descuento invalido: ' + dpRaw }); continue; }
      }
      discountStart = mapped['discount-start-date'] || '';
      discountEnd = mapped['discount-end-date'] || '';
    }
    const currency = p.currency || p.moneda || p.Currency || p.Moneda || 'EUR';
    const offerDescription = promoTag || '';

    const item = { sku, ean, price, discount_price: discountPrice, currency, offer_description: offerDescription, marketplace, quantity };

    if (outputFormat === 'sprinter_mirakl') {
      item.sprinterOffer = {
        'sku': sku,
        'product-id': ean,
        'product-id-type': ean ? 'EAN' : '',
        'description': offerDescription,
        'internal-description': '',
        'price': price,
        'price-additional-info': '',
        'quantity': quantity,
        'min-quantity-alert': '',
        'state': 'Nuevo',
        'available-start-date': '',
        'available-end-date': '',
        'logistic-class': '',
        'favorite-rank': '',
        'discount-price': discountPrice,
        'discount-start-date': discountStart,
        'discount-end-date': discountEnd,
        'discount-ranges': '',
        'leadtime-to-ship': '',
        'update-delete': '',
        'price[channel=INIT]': price,
        'discount-price[channel=INIT]': discountPrice,
        'discount-start-date[channel=INIT]': discountStart,
        'discount-end-date[channel=INIT]': discountEnd,
        'discount-ranges[channel=INIT]': '',
        'shipment-origin': shipmentOrigin,
        'vat-percentage': vatPct
      };
    }

    results.push({ json: item });
  } catch (err) { errors.push({ sku: p.sku || p.SKU || '?', message: err.message }); }
}

if (results.length === 0) results.push({ json: { _empty: true } });
results[results.length - 1].json._errors = errors;
results[results.length - 1].json._totalInput = products.length;
results[results.length - 1].json._marketplace = marketplace;
results[results.length - 1].json._includeDiscount = includeDiscount;
results[results.length - 1].json._promoTag = promoTag;
results[results.length - 1].json._outputFormat = outputFormat;
results[results.length - 1].json._shipmentOrigin = shipmentOrigin;
results[results.length - 1].json._vatPct = vatPct;
return results;

