let csvHeaders;
if (includeDiscount) { csvHeaders = isPT ? ['sku','preco','preco_desconto','moeda','descricao_oferta'] : ['sku','precio','precio_descuento','moneda','descripcion_oferta']; }
else { csvHeaders = isPT ? ['sku','preco','moeda'] : ['sku','precio','moneda']; }
const BOM = '﻿';
