const response = { status: 'completed', total: totalInput, success: products.length, errors: errors.length, errorList: errors, csvBase64, csvFilename: filename, products: products.slice(0, 6).map(p => { const c = { ...p }; delete c.sprinterOffer; return c; }), message: msg };

